import sys
from typing import List

class Solution:
    def parseBoolExpr(self, expression: str) -> List[bool]:
        if expression == '0':
            return [False]
        if expression == '1':
            return [True]
        if expression[0] == 'NOT':
            return [not x for x in self.parseBoolExpr(expression[4:-1])]
        sub_expressions = []
        operator = expression[1]
        current = ''
        depth = 0
        for char in expression[1:-1]:
            if char == ' ':
                continue
            if char == '(':
                depth += 1
                current += char
            elif char == ')':
                depth -= 1
                current += char
            else:
                current += char
            if char in ['(', ')'] and depth == 0:
                sub_expressions.append(self.parseBoolExpr(current))
                current = ''
        results = []
        for sub_expr in sub_expressions:
            for sub_result in sub_expr:
                if operator == 'AND':
                    results.append(results[-1] and sub_result if results else sub_result)
                elif operator == 'OR':
                    results.append(results[-1] or sub_result if results else sub_result)
        return results

if __name__ == '__main__':
    try:
        n = int(sys.stdin.readline().strip())
        expression = sys.stdin.readline().strip()
    except Exception as e:
        sys.exit(0)
    sol = Solution()
    ans = sol.parseBoolExpr(expression)
    print(len(ans))
    print('[', end='')
    for i, x in enumerate(ans):
        print(int(x), end='')
        if i != len(ans) - 1:
            print(', ', end='')
    print(']')

