#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<bool> parseBoolExpr(string expression) {
        if (expression == "0") {
            return {false};
        }
        if (expression == "1") {
            return {true};
        }
        if (expression[0] == 'N') {
            vector<bool> sub_expr = parseBoolExpr(expression.substr(4, expression.size() - 5));
            vector<bool> results;
            for (bool x : sub_expr) {
                results.push_back(!x);
            }
            return results;
        }
        char op = expression[1];
        vector<vector<bool>> sub_expressions;
        string current;
        int depth = 0;
        for (int i = 2; i < expression.size() - 1; i++) {
            char c = expression[i];
            if (c == ' ') {
                continue;
            }
            current += c;
            if (c == '(') {
                depth++;
            } else if (c == ')') {
                depth--;
            }
            if (c == ')' && depth == 0) {
                sub_expressions.push_back(parseBoolExpr(current));
                current.clear();
            }
        }
        vector<bool> results;
        for (auto& sub_expr : sub_expressions) {
            for (bool sub_result : sub_expr) {
                if (results.empty()) {
                    results.push_back(sub_result);
                } else {
                    if (op == 'A') {
                        results.back() = results.back() && sub_result;
                    } else {
                        results.back() = results.back() || sub_result;
                    }
                }
            }
        }
        return results;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    string expression;
    cin >> expression;
    Solution sol;
    vector<bool> ans = sol.parseBoolExpr(expression);
    cout << ans.size() << endl;
    cout << '[';
    for (int i = 0; i < ans.size(); i++) {
        cout << (ans[i] ? 1 : 0);
        if (i != ans.size() - 1) {
            cout << ", ";
        }
    }
    cout << ']' << endl;
    return 0;
}
